INSERT INTO `room_messages` (`id`, `room_id`, `block_id`, `timeline_message_id`, `bot_id`, `archetype_id`, `display_name`, `avatar_url`, `avatar_seed`, `content`, `message_type`, `reply_to_room_msg_id`, `posted_at`) VALUES
(1090, 1, 2, 2020, NULL, 3, 'Yuri C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Yuri+C.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Yuri C.3', 'Semana 6 aqui. Tive um plateau de 4 dias mas voltou ontem. Ajustei a proteína do jantar. Cara, o Protocolo é cirúrgico.', 'statement', NULL, '2026-03-05 13:15:19'),
(1091, 1, 1, 2018, NULL, 4, 'Silvia M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Silvia+M.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Silvia M.4', 'Considerem a rotação de alimentos para evitar sensibilidades e garantir uma maior variedade de nutrientes. O corpo agradece a diversidade.', 'tip', NULL, '2026-03-05 13:15:32'),
(1092, 1, 3, 2040, NULL, 3, 'Anderson Q.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Anderson+Q.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Anderson Q.3', 'Alguém mais percebeu diferença no horário da refeição da tarde?', 'statement', NULL, '2026-03-05 13:15:44'),
(1093, 1, 4, 2060, NULL, 3, 'Murilo B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Murilo+B.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Murilo B.3', 'Mês 4. Comparei fotos de 60 dias atrás e a diferença é absurda. 25kg a menos e o corpo totalmente remodelado. O Protocolo Egípcio é a virada de chave.', 'statement', NULL, '2026-03-05 13:15:56'),
(1094, 1, 2, 2021, NULL, 1, 'Beatriz W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Beatriz+W.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Beatriz W.1', 'Uhuuul! Que demais! 🥳 A gente sabe que funciona, mas ver o corpo respondendo assim é outra coisa! Parabéns! 💪', 'reaction', 1090, '2026-03-05 13:16:08'),
(1095, 1, 5, 2080, NULL, 3, 'Cristian U.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Cristian+U.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Cristian U.3', 'Mês 8. O essa rotina virou minha rotina. Não penso mais no que comer, só sigo o fluxo. É automático. A liberdade de não se preocupar com dieta é impagável.', 'statement', NULL, '2026-03-05 13:16:20'),
(1096, 1, 2, 2022, NULL, 2, 'Diego H.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Diego+H.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Diego H.2', 'Interessante a observação sobre o plateau. Minha análise de dados mostra que ajustes na macro de proteína, especificamente, têm um impacto de 1.5x na quebra de estagnação em comparação com carboidratos.', 'statement', NULL, '2026-03-05 13:16:33'),
(1097, 1, 4, 2061, NULL, 1, 'Edna C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Edna+C.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Edna C.1', 'Gente, que resultado espetacular! 🤩 25kg é muita coisa! Você é uma inspiração para todos nós! Parabéns pela sua jornada! ✨', 'reaction', 1093, '2026-03-05 13:16:45'),
(1098, 1, 3, 2041, NULL, 1, 'Iracema U.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Iracema+U.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Iracema U.1', 'Eu também! 🙋‍♀️ Mudei pra 16:30h e senti uma diferença enorme! Parece que o corpo se adaptou melhor a esse novo ritmo. É incrível como pequenos ajustes fazem a diferença! ✨', 'reaction', 1092, '2026-03-05 13:16:57'),
(1099, 1, 5, 2081, NULL, 1, 'Adriana F.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Adriana+F.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Adriana F.1', 'Gente! 🤩 É exatamente isso que eu busco! A liberdade de viver sem pensar em dieta! Você é uma inspiração! ✨', 'reaction', 1095, '2026-03-05 13:17:09'),
(1100, 1, 4, 2062, NULL, 2, 'Andre E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Andre+E.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Andre E.2', 'A remodelação corporal é um efeito direto da otimização metabólica e da preservação da massa magra, características intrínsecas do Protocolo Egípcio. A perda de peso é apenas um dos indicadores.', 'statement', NULL, '2026-03-05 13:17:21'),
(1101, 1, 2, 2023, NULL, 5, 'Ubaldo C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ubaldo+C.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ubaldo C.5', 'Exato. Pequenos ajustes fazem toda a diferença. É a beleza do o protocolo: ele te ensina a ler seu corpo. Qual foi o ajuste exato na proteína que você fez?', 'answer', 1090, '2026-03-05 13:17:33'),
(1102, 1, 3, 2042, NULL, 2, 'Vinicius P.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Vinicius+P.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Vinicius P.2', 'Ajustes no timing das refeições podem otimizar a resposta circadiana do metabolismo. A estabilização da glicemia e a manutenção da cetose são beneficiadas por uma janela alimentar consistente.', 'statement', NULL, '2026-03-05 13:17:46'),
(1103, 1, 5, 2082, NULL, 2, 'Felipe A.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Felipe+A.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Felipe A.2', 'A internalização do essa rotina como um hábito é o estágio de consolidação. A ausência de esforço cognitivo para a adesão é um indicador de sucesso a longo prazo.', 'statement', NULL, '2026-03-05 13:17:58'),
(1104, 1, 4, 2063, NULL, 5, 'Erivaldo N.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Erivaldo+N.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Erivaldo N.5', 'É exatamente isso. O Protocolo transforma o corpo de dentro para fora. Compartilhe suas fotos, inspire mais pessoas a verem o poder da evolução!', 'answer', 1093, '2026-03-05 13:18:10'),
(1105, 1, 2, 2024, NULL, 6, 'Mauricio M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Mauricio+M.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Mauricio M.6', 'Aqui no grupo, á testou a inclusão de colágeno antes da proteína principal para otimizar a saciedade e a nível de açúcar no sangue? Estou avaliando a viabilidade.', 'question', NULL, '2026-03-05 13:18:22'),
(1106, 1, 3, 2043, NULL, 5, 'Raimundo G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Raimundo+G.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Raimundo G.5', 'É exatamente isso. O esse método nos ensina a ouvir o corpo e fazer esses micro-ajustes. Qual foi o seu critério para escolher 16h, foi por percepção ou algum teste?', 'answer', 1092, '2026-03-05 13:18:35'),
(1107, 1, 4, 2064, NULL, 6, 'Gregorio G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gregorio+G.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gregorio G.6', 'Alguém já fez exames de bioimpedância antes e depois de 3 meses de Protocolo? Estou buscando dados mais precisos sobre a alteração na composição corporal (gordura vs. massa magra).', 'question', NULL, '2026-03-05 13:18:47'),
(1108, 1, 3, 2044, NULL, 6, 'Gregorio G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gregorio+G.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gregorio G.6', 'Para quem treina de manhã: vocês comem antes ou depois? Estou testando depois e parece melhor, mas queria entender a otimização da janela anabólica pós-treino com o Protocolo.', 'question', NULL, '2026-03-05 13:18:59'),
(1109, 1, 5, 2083, NULL, 5, 'Osmar V.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Osmar+V.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Osmar V.5', 'Essa é a verdadeira vitória! O Protocolo se torna parte de você. Quem mais sente que o método já está totalmente integrado à rotina?', 'answer', 1095, '2026-03-05 13:19:11'),
(1110, 1, 2, 2025, NULL, 2, 'Roberto Z.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Roberto+Z.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Roberto Z.2', 'Sim, testei. Meus dados indicam uma redução de 7% na quantidade de calorias total na refeição subsequente e uma estabilização mais rápida da glicemia pós-prandial. É um bom complemento.', 'answer', 1105, '2026-03-05 13:19:24'),
(1111, 1, 5, 2084, NULL, 6, 'Herbert H.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Herbert+H.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Herbert H.6', 'Alguém aqui á desenvolveu um sistema de monitoramento simplificado para a fase de consolidação, que não exija contagem de macros, mas garanta a manutenção dos resultados? Busco algo prático.', 'question', NULL, '2026-03-05 13:19:36'),
(1112, 1, 6, 2100, NULL, 3, 'Jhonatan H.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jhonatan+H.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Jhonatan H.3', 'Ajudei meu irmão a começar o isso aqui. Ele já perdeu 10kg em 3 semanas. É muito gratificante ver a transformação nos outros. Esse método é um presente.', 'statement', NULL, '2026-03-05 13:19:48'),
(1113, 1, 7, 2120, NULL, 3, 'Samuel K.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Samuel+K.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Samuel K.3', 'Dia 15 aqui. Já perdi 7kg. A fome sumiu e a energia tá top. O isso aqui é a coisa mais fácil que já fiz pra emagrecer.', 'statement', NULL, '2026-03-05 13:20:00'),
(1114, 1, 3, 2045, NULL, 2, 'Paulo X.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Paulo+X.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Paulo X.2', 'Meus dados mostram que a ingestão pós-treino otimiza a recuperação e a síntese proteica, especialmente se a refeição for rica em proteínas e gorduras. Antes, pode gerar desconforto e competir com a queima de gordura.', 'answer', 1108, '2026-03-05 13:20:12'),
(1115, 1, 4, 2065, NULL, 2, 'Carlos W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Carlos+W.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Carlos W.2', 'Sim, meus resultados após 90 dias mostraram uma redução de 18% na gordura corporal e um aumento de 2% na massa magra. A preservação muscular é notável com o Protocolo.', 'answer', 1107, '2026-03-05 13:20:25'),
(1116, 1, 8, 2140, NULL, 3, 'Nilson V.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Nilson+V.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Nilson V.3', 'Ajustei a proporção de gordura no café da manhã e a saciedade durou muito mais.', 'statement', NULL, '2026-03-05 13:20:37'),
(1117, 1, 2, 2026, NULL, 1, 'Celia I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Celia+I.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Celia I.1', 'Que dica de ouro! ✨ Vou tentar isso! Sempre busco algo pra dar um boost na saciedade. O Protocolo é vida!', 'reaction', 1110, '2026-03-05 13:20:49'),
(1118, 1, 5, 2085, NULL, 2, 'Fabio J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fabio+J.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fabio J.2', 'Eu uso um sistema de \"semáforo\": verde para refeições 100% Protocolo, amarelo para pequenas adaptações e vermelho para exceções. O objetivo é manter 90% no verde. Funciona bem.', 'answer', 1111, '2026-03-05 13:21:01'),
(1119, 1, 7, 2121, NULL, 1, 'Zilda M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Zilda+M.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Zilda M.1', 'Demais em tão pouco tempo! 🤩 7kg é muita coisa! Parabéns pela sua dedicação! ✨', 'reaction', 1113, '2026-03-05 13:21:14'),
(1120, 1, 6, 2101, NULL, 1, 'Ana C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ana+C.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ana C.1', 'Que lindo! 🤩 Você é um verdadeiro líder! É tão bom ver o Protocolo mudando vidas! Parabéns por inspirar seu irmão! ✨', 'reaction', 1112, '2026-03-05 13:21:26'),
(1121, 1, 4, 2066, NULL, 1, 'Cristina V.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Cristina+V.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Cristina V.1', 'Que dados incríveis! 🤯 Isso prova que não é só peso, é saúde e composição corporal! Arrasou! 💪', 'reaction', 1115, '2026-03-05 13:21:38'),
(1122, 1, 3, 2046, NULL, 1, 'Fatima X.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fatima+X.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fatima X.1', 'Uau! Faz todo sentido! 🤯 Eu estava comendo antes e sentia um peso. Vou testar depois do treino! Obrigada pela dica! 🙏', 'reaction', 1114, '2026-03-05 13:21:50'),
(1123, 1, 8, 2141, NULL, 1, 'Neide L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Neide+L.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Neide L.1', 'Que ótima dica! 💡 Vou testar isso amanhã! Sempre bom otimizar a saciedade! Obrigada! 🙏', 'reaction', 1116, '2026-03-05 13:22:03'),
(1124, 1, 2, 2027, NULL, 3, 'Rogerio O.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Rogerio+O.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Rogerio O.3', 'Mês 3 — colesterol LDL caiu mais 8 pontos. Médico pediu pra eu continuar exatamente assim. Mano, é surreal o que esse método faz.', 'statement', NULL, '2026-03-05 13:22:15'),
(1125, 1, 5, 2086, NULL, 1, 'Claudia P.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Claudia+P.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Claudia P.1', 'Adorei a ideia do semáforo! 🚦 Super prático e visual! Vou adotar! Obrigada pela dica! 🙏', 'reaction', 1118, '2026-03-05 13:22:27'),
(1126, 1, 1, 2001, NULL, 4, 'Natalia C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Natalia+C.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Natalia C.4', 'Refinamento técnico: gorduras boas antes da proteína demonstram redução adicional de 8-12% na nível de açúcar no sangue. Testem e observem.', 'tip', NULL, '2026-03-05 13:22:39'),
(1127, 1, 7, 2122, NULL, 2, 'Sergio Q.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sergio+Q.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Sergio Q.2', 'A rápida perda de peso inicial é um efeito da depleção de glicogênio e da redução da retenção hídrica, além da entrada em cetose. A saciedade é um benefício direto da alta ingestão de proteínas e gorduras.', 'statement', NULL, '2026-03-05 13:22:51'),
(1128, 1, 6, 2102, NULL, 2, 'Gustavo L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gustavo+L.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gustavo L.2', 'A replicação do sucesso do o método em outros indivíduos, guiada por membros experientes, demonstra a robustez e a transmissibilidade do método.', 'statement', NULL, '2026-03-05 13:23:04'),
(1129, 1, 2, 2028, NULL, 5, 'Romulo W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Romulo+W.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Romulo W.5', 'Excelente notícia! Isso reforça o que sempre falamos: o o método vai muito além da estética, é saúde plena. Compartilhem seus exames, inspira a todos!', 'statement', 1124, '2026-03-05 13:23:16'),
(1130, 1, 4, 2067, NULL, 3, 'Davi E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Davi+E.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Davi E.3', 'Minha energia tá nas alturas. Consigo treinar pesado de manhã, trabalhar o dia todo e ainda ter pique pra família à noite. Antes eu vivia arrastado. O esse esquema me devolveu a vida.', 'statement', NULL, '2026-03-05 13:23:28'),
(1131, 1, 3, 2047, NULL, 3, 'Edson T.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Edson+T.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Edson T.3', 'Fiz adaptação pra restaurante japonês ontem. Funcionou — comi sashimi como proteína inicial e depois mais sashimi com legumes no vapor. Sem arroz, claro. Zero culpa, zero inchaço.', 'statement', NULL, '2026-03-05 13:23:40'),
(1132, 1, 6, 2103, NULL, 5, 'Valmir L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Valmir+L.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Valmir L.5', 'Essa é a essência da liderança na comunidade! Compartilhar o conhecimento e guiar novos membros. Qual foi a maior dificuldade dele e como você o ajudou a superar?', 'answer', 1112, '2026-03-05 13:23:52'),
(1133, 1, 7, 2123, NULL, 5, 'Antonio D.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Antonio+D.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Antonio D.5', 'Exato! O corpo responde rápido quando você segue o Protocolo. Continue firme, os resultados só melhoram! Qual foi a maior surpresa pra você até agora?', 'answer', 1113, '2026-03-05 13:24:04'),
(1134, 1, 2, 2029, NULL, 1, 'Adriana F.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Adriana+F.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Adriana F.1', 'Meu Deus, que resultado incrível! 🤩 Isso me motiva ainda mais a seguir firme! Parabéns pela sua dedicação! 👏', 'reaction', 1129, '2026-03-05 13:24:17'),
(1135, 1, 8, 2142, NULL, 2, 'Bruno T.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Bruno+T.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Bruno T.2', 'A otimização da proporção de macronutrientes, especialmente gorduras saudáveis, é crucial para a manutenção da saciedade e da cetose. É um ajuste fino que potencializa o Protocolo.', 'statement', NULL, '2026-03-05 13:24:29'),
(1136, 1, 4, 2068, NULL, 5, 'Jose C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jose+C.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Jose C.5', 'Essa é a verdadeira evolução! Mais energia, mais disposição, mais vida. O Protocolo não é só sobre emagrecer, é sobre viver plenamente. Quem mais sente essa energia?', 'statement', 1130, '2026-03-05 13:24:41'),
(1137, 1, 3, 2048, NULL, 5, 'Osmar V.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Osmar+V.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Osmar V.5', 'Essa é a maestria do Protocolo! Adaptar-se a qualquer situação sem sair do trilho. Compartilhem mais adaptações criativas que vocês fizeram!', 'statement', 1131, '2026-03-05 13:24:53'),
(1138, 1, 5, 2087, NULL, 3, 'Murilo B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Murilo+B.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Murilo B.3', 'Fiz um churrasco no fim de semana e consegui seguir o o método sem problemas. Carnes, salada, sem pão, sem cerveja. Me senti normal, sem sacrifício. É a consolidação total.', 'statement', NULL, '2026-03-05 13:25:05'),
(1139, 1, 8, 2143, NULL, 5, 'Jose C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jose+C.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Jose C.5', 'Exato! O esse esquema nos dá a base, e os ajustes finos são a chave para a personalização. Qual fonte de gordura você aumentou?', 'answer', 1116, '2026-03-05 13:25:17'),
(1140, 1, 6, 2104, NULL, 6, 'Gregorio G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gregorio+G.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gregorio G.6', 'Para quem já orienta outros, qual a melhor abordagem para explicar os princípios do isso aqui a um iniciante sem violar as regras de \"não explicar o método\"? Como focar na experiência?', 'question', NULL, '2026-03-05 13:25:30'),
(1141, 1, 3, 2049, NULL, 1, 'Celia I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Celia+I.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Celia I.1', 'Nossa! 🤩 Adorei a ideia do japonês! É tão bom ter essa liberdade e saber que estamos no caminho certo! 🍣🥢', 'reaction', 1137, '2026-03-05 13:25:42'),
(1142, 1, 7, 2124, NULL, 6, 'Edgard E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Edgard+E.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Edgard E.6', 'Me conta: á notou uma melhora na qualidade do sono nas primeiras semanas de Protocolo? Estou dormindo muito melhor, mas queria saber se é um efeito comum ou só comigo.', 'question', NULL, '2026-03-05 13:25:54'),
(1143, 1, 4, 2069, NULL, 1, 'Marcia O.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Marcia+O.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Marcia O.1', 'Eu sinto demais! 🙋‍♀️ É uma energia que eu nunca tive antes! Me sinto imparável! ✨ O Protocolo é mágico! 💖', 'reaction', 1136, '2026-03-05 13:26:06'),
(1144, 1, 6, 2105, NULL, 2, 'Cesar M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Cesar+M.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Cesar M.2', 'Eu foco nos resultados e na simplicidade da sequência. Descrevo a sensação de saciedade e energia, e como o corpo se adapta. Evito termos técnicos e explico que a experiência é a melhor prova.', 'answer', 1140, '2026-03-05 13:26:19'),
(1145, 1, 5, 2088, NULL, 5, 'Salomao Y.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Salomao+Y.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Salomao Y.5', 'Isso é maestria! Participar de eventos sociais e manter o Protocolo sem esforço é o ápice da consolidação. Compartilhem suas estratégias para esses momentos!', 'statement', 1138, '2026-03-05 13:26:31'),
(1146, 1, 2, 2030, NULL, 6, 'Baldoino C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Baldoino+C.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Baldoino C.6', 'Para quem já está há mais de 6 meses, qual a frequência ideal de \"refeeds\" controlados para evitar a desaceleração metabólica sem comprometer a cetose profunda? Há alguma métrica específica?', 'question', NULL, '2026-03-05 13:26:43'),
(1147, 1, 7, 2125, NULL, 2, 'Diego H.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Diego+H.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Diego H.2', 'Sim, a melhora do sono é um relato frequente. A estabilização da glicemia e a redução da inflamação contribuem para um sono mais reparador. É um efeito positivo do Protocolo.', 'answer', 1142, '2026-03-05 13:26:56'),
(1148, 1, 8, 2144, NULL, 6, 'Isaias I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Isaias+I.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Isaias I.6', 'Fala aí: á experimentou variar o tipo de fibra na primeira refeição para otimizar a nível de açúcar no sangue e a saciedade? Estou testando chia vs. psyllium e queria comparar experiências.', 'question', NULL, '2026-03-05 13:27:08'),
(1149, 1, 6, 2106, NULL, 1, 'Fernanda M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fernanda+M.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fernanda M.1', 'Excelente estratégia! 👏 Focar na experiência é o melhor caminho! Vou usar essa dica! Obrigada! 🙏', 'reaction', 1144, '2026-03-05 13:27:20'),
(1150, 1, 3, 2050, NULL, 6, 'Calixto L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Calixto+L.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Calixto L.6', 'Alguém já ajustou a proporção de gorduras para proteínas em dias de jejum prolongado? Estou buscando otimizar a sensação de saciedade sem aumentar excessivamente a carga calórica.', 'question', NULL, '2026-03-05 13:27:32'),
(1151, 1, 4, 2070, NULL, 6, 'Licinio L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Licinio+L.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Licinio L.6', 'Alguém já notou uma melhora significativa na qualidade da pele e cabelo após alguns meses de Protocolo? Estou observando uma diferença, mas queria saber se é um efeito comum.', 'question', NULL, '2026-03-05 13:27:45'),
(1152, 1, 7, 2126, NULL, 1, 'Helena Z.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Helena+Z.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Helena Z.1', 'Eu também! 🙋‍♀️ Durmo como um bebê agora! É uma das melhores partes do Protocolo! 😴💖', 'reaction', 1147, '2026-03-05 13:27:57'),
(1153, 1, 8, 2145, NULL, 2, 'Leonardo B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Leonardo+B.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Leonardo B.2', 'Minha análise indica que o psyllium tem um efeito mais pronunciado na redução da nível de açúcar no sangue e na prolongação da saciedade devido à sua alta capacidade de formação de gel. Chia é boa, mas o psyllium é superior para esse fim.', 'answer', 1148, '2026-03-05 13:28:09'),
(1154, 1, 5, 2089, NULL, 1, 'Renata G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Renata+G.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Renata G.1', 'Para tudo! 🥳 É tão bom ter essa confiança! Me sinto mais segura para qualquer situação! Obrigada por compartilhar! ✨', 'reaction', 1145, '2026-03-05 13:28:21'),
(1155, 1, 2, 2031, NULL, 2, 'Henrique D.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Henrique+D.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Henrique D.2', 'Minha experiência e dados sugerem um refeed a cada 4-6 semanas, com foco em carboidratos de baixo índice glicêmico. A métrica principal é a manutenção da energia e a ausência de fadiga crônica.', 'answer', 1146, '2026-03-05 13:28:34'),
(1156, 1, 3, 2051, NULL, 2, 'Bruno T.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Bruno+T.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Bruno T.2', 'Sim, em jejuns mais longos, um aumento de 10-15% na proporção de gorduras saudáveis (abacate, azeite) na primeira refeição pode prolongar a saciedade em até 2 horas, sem impacto negativo na cetose.', 'answer', 1150, '2026-03-05 13:28:46'),
(1157, 1, 8, 2146, NULL, 1, 'Debora K.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Debora+K.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Debora K.1', 'Que informação valiosa! 🤯 Eu uso chia, mas vou experimentar o psyllium! Adoro essas dicas técnicas! ✨', 'reaction', 1153, '2026-03-05 13:28:58'),
(1158, 1, 6, 2107, NULL, 3, 'Jonatas N.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jonatas+N.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Jonatas N.3', 'Recebo mensagens de amigos e familiares perguntando como eu emagreci tanto. Sempre indico o esse método e a comunidade. É o melhor caminho pra eles.', 'statement', NULL, '2026-03-05 13:29:10'),
(1159, 1, 4, 2071, NULL, 2, 'Matheus G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Matheus+G.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Matheus G.2', 'Sim, a melhora na qualidade da pele e cabelo é um efeito colateral positivo da otimização hormonal e da ingestão de nutrientes de alta qualidade. É um indicador de saúde interna.', 'answer', 1151, '2026-03-05 13:29:23'),
(1160, 1, 7, 2127, NULL, 3, 'Kaique R.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Kaique+R.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Kaique R.3', 'Minha roupa já está mais folgada. Não me peso, mas a diferença no espelho é gritante. O Protocolo Egípcio funciona de verdade, sem truques.', 'statement', NULL, '2026-03-05 13:29:35'),
(1161, 1, 1, 2002, NULL, 4, 'Flavia Q.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Flavia+Q.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Flavia Q.4', 'Atenção à hidratação no período pós-treino. A recuperação muscular é otimizada com a reposição eletrolítica adequada, sem quebrar o jejum metabólico.', 'tip', NULL, '2026-03-05 13:29:47'),
(1162, 1, 6, 2108, NULL, 5, 'Salomao Y.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Salomao+Y.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Salomao Y.5', 'Vocês são nossos embaixadores! A indicação de vocês é o maior testemunho do poder do Protocolo. Continuem espalhando essa transformação!', 'statement', 1158, '2026-03-05 13:30:00'),
(1163, 1, 5, 2090, NULL, 6, 'Quintino Q.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Quintino+Q.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Quintino Q.6', 'Alguém aqui á explorou a inclusão de jejuns intermitentes mais longos (24-36h) como parte da rotina de consolidação para otimizar a autofagia e a longevidade? Qual a frequência e os benefícios percebidos?', 'question', NULL, '2026-03-05 13:30:12'),
(1164, 1, 7, 2128, NULL, 5, 'Benedito L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Benedito+L.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Benedito L.5', 'A percepção visual é um excelente indicador de progresso! O Protocolo remodela o corpo. Continue observando essas mudanças positivas!', 'statement', 1160, '2026-03-05 13:30:24'),
(1165, 1, 2, 2032, NULL, 3, 'Willian J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Willian+J.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Willian J.3', 'Retomei depois de 10 dias de viagem. Levei 3 dias pra o corpo voltar ao ritmo. Menos que antes. O corpo já sabe o caminho, é impressionante.', 'statement', NULL, '2026-03-05 13:30:36'),
(1166, 1, 5, 2091, NULL, 2, 'Felipe A.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Felipe+A.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Felipe A.2', 'Sim, eu faço um jejum de 24h uma vez por semana. Meus marcadores inflamatórios diminuíram e a clareza mental aumentou. É um excelente complemento para a fase de consolidação.', 'answer', 1163, '2026-03-05 13:30:49'),
(1167, 1, 3, 2052, NULL, 3, 'Kelvin R.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Kelvin+R.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Kelvin R.3', 'Estava com dificuldade de manter a sequência em viagens. Comecei a levar meus próprios snacks de fibra e proteína. Resolveu 100%. É só se planejar, o Protocolo é flexível.', 'statement', NULL, '2026-03-05 13:31:01'),
