(1318, 1, 11, 2214, NULL, 1, 'Beatriz W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Beatriz+W.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Beatriz W.1', 'Que honra! 🤩 Você é uma verdadeira embaixadora do Protocolo! Parabéns! 🥳', 'reaction', 1313, '2026-03-05 14:01:52'),
