(1323, 1, 9, 2176, NULL, 3, 'Gerson I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gerson+I.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gerson I.3', 'Já estou no meu peso de quando tinha 20 anos! E com muito mais saúde e energia. O esse método é a fonte da juventude.', 'statement', NULL, '2026-03-05 14:02:53'),
