(1365, 1, 13, 2259, NULL, 1, 'Maria L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Maria+L.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Maria L.1', 'que orgulho 🔥', 'reaction', 1356, '2026-03-05 14:11:27'),
(1366, 1, 16, 2302, NULL, 2, 'Wagner L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Wagner+L.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Wagner L.2', 'A replicação do sucesso do essa rotina em outros indivíduos, guiada por membros experientes, demonstra a robustez e a transmissibilidade do método.', 'statement', NULL, '2026-03-05 14:11:39'),
(1367, 1, 15, 2283, NULL, 5, 'Gilberto I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gilberto+I.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gilberto I.5', 'Segue o ritmo pessoal.', 'answer', 1355, '2026-03-05 14:11:51'),
(1368, 1, 14, 2279, NULL, 1, 'Simone B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Simone+B.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Simone B.1', 'to babando', 'reaction', 1361, '2026-03-05 14:12:04'),
(1369, 1, 17, 2322, NULL, 2, 'Fabio J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fabio+J.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fabio J.2', 'A redução de medidas e gordura localizada é um efeito da queima de gordura e da remodelação corporal. A perda de peso é consistente com a entrada em cetose e a otimização metabólica.', 'statement', NULL, '2026-03-05 14:12:16'),
(1370, 1, 15, 2284, NULL, 6, 'Isaias I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Isaias+I.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Isaias I.6', 'Alguém já desenvolveu um plano de \"manutenção avançada\" para a fase de consolidação, que inclua ciclagem de macros ou jejuns mais longos para otimizar a longevidade? Busco algo mais sofisticado.', 'question', NULL, '2026-03-05 14:12:28'),
(1371, 1, 18, 2340, NULL, 3, 'Willian J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Willian+J.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Willian J.3', 'Ajustei a quantidade de proteína no almoço e a saciedade durou muito mais. Antes, sentia uma leve fome antes do jantar. Pequenos ajustes, grandes resultados.', 'statement', NULL, '2026-03-05 14:12:40'),
(1372, 1, 16, 2303, NULL, 5, 'Erivaldo N.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Erivaldo+N.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Erivaldo N.5', 'Essa é a essência da liderança na comunidade! Compartilhar o conhecimento e guiar novos membros. Qual foi a maior dificuldade deles e como você os ajudou a superar?', 'answer', 1358, '2026-03-05 14:12:52');
INSERT INTO `room_messages` (`id`, `room_id`, `block_id`, `timeline_message_id`, `bot_id`, `archetype_id`, `display_name`, `avatar_url`, `avatar_seed`, `content`, `message_type`, `reply_to_room_msg_id`, `posted_at`) VALUES
(1373, 1, 1, 2010, NULL, 4, 'Mariana M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Mariana+M.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Mariana M.4', 'A gestão do estresse é um pilar esquecido. Níveis elevados de cortisol podem sabotar os resultados, mesmo com adesão perfeita ao Protocolo. Meditem, relaxem.', 'tip', NULL, '2026-03-05 14:13:05'),
(1374, 1, 17, 2323, NULL, 5, 'Geraldo O.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Geraldo+O.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Geraldo O.5', 'Exato! O corpo responde rápido quando você segue o Protocolo. Continue firme, os resultados só melhoram! Qual foi a maior mudança que você sentiu nas medidas?', 'answer', 1359, '2026-03-05 14:13:17'),
(1375, 1, 15, 2285, NULL, 2, 'Andre E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Andre+E.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Andre E.2', 'Eu adoto a ciclagem de carboidratos em dias de treino intenso e jejuns de 24h semanais. Meus marcadores de saúde se mantêm ótimos e a energia é constante. É um ajuste avançado do Protocolo.', 'answer', 1370, '2026-03-05 14:13:29'),
(1376, 1, 16, 2304, NULL, 6, 'Mauricio M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Mauricio+M.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Mauricio M.6', 'Para quem já orienta outros, qual a melhor forma de abordar a questão da \"resistência inicial\" ao o protocolo? Como mostrar que é mais fácil do que parece?', 'question', NULL, '2026-03-05 14:13:41'),
(1377, 1, 17, 2324, NULL, 6, 'Fernando F.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fernando+F.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fernando F.6', 'Alguém aqui á notou uma melhora na libido e na função hormonal nas primeiras semanas de Protocolo? Estou sentindo uma diferença significativa.', 'question', NULL, '2026-03-05 14:13:53'),
(1378, 1, 18, 2341, NULL, 1, 'Beatriz W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Beatriz+W.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Beatriz W.1', 'demais mesmo!', 'reaction', 1371, '2026-03-05 14:14:06'),
(1379, 1, 19, 2360, NULL, 3, 'Wesley M.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Wesley+M.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Wesley M.3', 'Mês 7. Minha glicemia de jejum caiu de 120 para 80. O médico disse que estou pré-diabético revertido e com risco cardiovascular reduzido. O Protocolo Egípcio é um milagre na minha vida.', 'statement', NULL, '2026-03-05 14:14:18'),
(1380, 1, 15, 2286, NULL, 1, 'Helena Z.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Helena+Z.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Helena Z.1', 'Adorei a ideia da ciclagem e jejuns! 💡 É um ótimo equilíbrio! Vou tentar isso! Obrigada! 🙏', 'reaction', 1375, '2026-03-05 14:14:30'),
(1381, 1, 18, 2342, NULL, 2, 'Sergio Q.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sergio+Q.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Sergio Q.2', 'A ajuste da quantidade de macronutrientes, especialmente proteínas, é crucial para a manutenção da saciedade e da cetose. É um ajuste fino que potencializa o Protocolo.', 'statement', NULL, '2026-03-05 14:14:42'),
(1382, 1, 16, 2305, NULL, 2, 'Jorge Y.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jorge+Y.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Jorge Y.2', 'Eu foco nos primeiros resultados rápidos e na sensação de saciedade e energia. Explico que a adaptação é rápida e que o corpo se acostuma. Meus dados mostram que essa abordagem aumenta a adesão.', 'answer', 1376, '2026-03-05 14:14:55'),
(1383, 1, 19, 2361, NULL, 1, 'Ana C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ana+C.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ana C.1', 'Demais! 🤩 Reverter o pré-diabetes e reduzir o risco cardiovascular é uma conquista gigantesca! Você é uma inspiração! Parabéns! ✨', 'reaction', 1379, '2026-03-05 14:15:07'),
(1384, 1, 17, 2325, NULL, 2, 'Marcelo F.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Marcelo+F.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Marcelo F.2', 'Sim, a melhora da libido e da função hormonal é um relato comum. A otimização hormonal e a redução da inflamação contribuem para esses benefícios. É um efeito positivo do Protocolo.', 'answer', 1377, '2026-03-05 14:15:19'),
(1385, 1, 15, 2287, NULL, 3, 'Tiago G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Tiago+G.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Tiago G.3', 'Fui a um cruzeiro de 7 dias e não engordei 1 grama. Mantive o Protocolo Egípcio com adaptações simples. É a prova que o método te blinda contra o efeito sanfona, mesmo em situações extremas.', 'statement', NULL, '2026-03-05 14:15:31'),
(1386, 1, 16, 2306, NULL, 1, 'Sandra R.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sandra+R.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Sandra R.1', 'Excelente abordagem! 👏 Focar nos resultados é fundamental! Vou usar essa dica! Obrigada! 🙏', 'reaction', 1382, '2026-03-05 14:15:43'),
(1387, 1, 18, 2343, NULL, 5, 'Nivaldo U.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Nivaldo+U.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Nivaldo U.5', 'Exato! O esse método nos dá a base, e os ajustes finos são a chave para a personalização. Qual fonte de proteína você aumentou?', 'answer', 1371, '2026-03-05 14:15:55'),
(1388, 1, 19, 2362, NULL, 2, 'Leonardo B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Leonardo+B.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Leonardo B.2', 'A reversão da pré-diabetes e a redução do risco cardiovascular são dos benefícios mais significativos do o PE, demonstrando a profunda melhora na sensibilidade à insulina e no controle glicêmico.', 'statement', NULL, '2026-03-05 14:16:08'),
(1389, 1, 17, 2326, NULL, 1, 'Tatiana E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Tatiana+E.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Tatiana E.1', 'Eu também! 🙋‍♀️ Me sinto muito mais disposta e com mais energia! É uma maravilha! 💖', 'reaction', 1384, '2026-03-05 14:16:20'),
(1390, 1, 16, 2307, NULL, 3, 'Kaua F.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Kaua+F.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Kaua F.3', 'Recebo mensagens de pessoas de outros estados pedindo dicas sobre o Protocolo Egípcio. Me sinto um influenciador de saúde. É uma forma de liderar e ajudar em grande escala.', 'statement', NULL, '2026-03-05 14:16:32'),
(1391, 1, 15, 2288, NULL, 5, 'Geraldo O.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Geraldo+O.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Geraldo O.5', 'Essa é a segurança que o isso aqui oferece!', 'statement', 1385, '2026-03-05 14:16:44'),
(1392, 1, 18, 2344, NULL, 6, 'Pompilio P.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Pompilio+P.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Pompilio P.6', 'Rola aqui também? á experimentou variar o tipo de gordura na primeira refeição para otimizar a resposta metabólica e a saciedade? Estou testando abacate vs. azeite e queria comparar experiências.', 'question', NULL, '2026-03-05 14:16:57'),
(1393, 1, 19, 2363, NULL, 5, 'Francisco E.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Francisco+E.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Francisco E.5', 'Essa é a verdadeira evolução!', 'answer', 1379, '2026-03-05 14:17:09'),
(1394, 1, 1, 2011, NULL, 4, 'Hosana S.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Hosana+S.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Hosana S.4', 'Reavaliem a qualidade das suas gorduras. Óleos refinados e processados são inimigos do Protocolo. Priorizem fontes naturais e virgens.', 'tip', NULL, '2026-03-05 14:17:21'),
(1395, 1, 17, 2327, NULL, 3, 'Renan A.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Renan+A.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Renan A.3', 'Minha pele está muito mais bonita e radiante. As pessoas estão elogiando. O Protocolo Egípcio me deu um brilho que eu não tinha.', 'statement', NULL, '2026-03-05 14:17:33'),
(1396, 1, 15, 2289, NULL, 1, 'Fatima X.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fatima+X.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fatima X.1', 'isso me motiva demais', 'reaction', 1391, '2026-03-05 14:17:45'),
(1397, 1, 16, 2308, NULL, 5, 'Marcio T.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Marcio+T.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Marcio T.5', 'Essa é a liderança em ação! O Protocolo Egípcio se espalhando através da sua influência. Continuem construindo essa rede de transformação!', 'statement', 1390, '2026-03-05 14:17:58'),
(1398, 1, 18, 2345, NULL, 2, 'Fabio J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fabio+J.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fabio J.2', 'Minha análise indica que o abacate tende a promover uma saciedade mais prolongada devido à sua combinação de fibras e gorduras saudáveis. Azeite é bom, mas abacate é superior para esse fim na primeira refeição.', 'answer', 1392, '2026-03-05 14:18:10'),
(1399, 1, 17, 2328, NULL, 5, 'Romulo W.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Romulo+W.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Romulo W.5', 'Essa é a beleza que vem de dentro! O Protocolo Egípcio transformando a pele e a aparência. Continue brilhando!', 'statement', 1395, '2026-03-05 14:18:22'),
(1400, 1, 19, 2364, NULL, 6, 'Ulisses U.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ulisses+U.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ulisses U.6', 'Alguém aqui á fez exames de perfil lipídico completo (HDL, LDL, triglicerídeos) antes e depois de 9 meses de Protocolo? Estou buscando dados sobre a otimização do perfil cardiovascular a longo prazo.', 'question', NULL, '2026-03-05 14:18:34'),
(1401, 1, 15, 2290, NULL, 6, 'Ricardo A.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ricardo+A.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ricardo A.6', 'Alguém já explorou a inclusão de dias de \"refeed\" estratégico com carboidratos complexos na fase de consolidação para otimizar a função da tireoide e a leptina?', 'question', NULL, '2026-03-05 14:18:46'),
(1402, 1, 16, 2309, NULL, 1, 'Ana C.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ana+C.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ana C.1', 'arrasou!', 'reaction', 1397, '2026-03-05 14:18:59'),
(1403, 1, 19, 2365, NULL, 2, 'Gustavo L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Gustavo+L.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Gustavo L.2', 'Sim, meus exames após 9 meses mostraram uma redução de 40% nos triglicerídeos, aumento de 20% no HDL e estabilização do LDL. O Protocolo é excelente para a saúde cardiovascular.', 'answer', 1400, '2026-03-05 14:19:11'),
(1404, 1, 16, 2310, NULL, 6, 'Norberto N.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Norberto+N.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Norberto N.6', 'Me conta: á desenvolveu um \"mini-curso\" ou série de vídeos curtos sobre o Protocolo Egípcio (sem explicar os fundamentos) para compartilhar com novos interessados? Busco algo didático e engajador.', 'question', NULL, '2026-03-05 14:19:23'),
(1405, 1, 18, 2346, NULL, 1, 'Simone B.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Simone+B.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Simone B.1', 'Que informação valiosa! 🤯 Eu uso azeite, mas vou experimentar abacate! Adoro essas dicas técnicas! ✨', 'reaction', 1398, '2026-03-05 14:19:35'),
(1406, 1, 17, 2329, NULL, 1, 'Debora K.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Debora+K.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Debora K.1', 'Para tudo! 😍 A pele bonita é a melhor sensação! Parabéns! ✨', 'reaction', 1399, '2026-03-05 14:19:48'),
(1407, 1, 15, 2291, NULL, 2, 'Fabio J.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Fabio+J.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Fabio J.2', 'Sim, faço um refeed a cada 3-4 semanas com carboidratos de baixo índice glicêmico.', 'answer', 1401, '2026-03-05 14:20:00'),
(1408, 1, 16, 2311, NULL, 2, 'Renato I.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Renato+I.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Renato I.2', 'Eu criei uma série de 3 vídeos curtos: \"O que esperar nos primeiros 7 dias\", \"Como lidar com desafios\" e \"A vida após 30 dias\". Foco na experiência e nos resultados. O feedback é muito positivo.', 'answer', 1404, '2026-03-05 14:20:12'),
(1409, 1, 18, 2347, NULL, 3, 'Wendel P.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Wendel+P.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Wendel P.3', 'Adaptei a receita de pizza do Protocolo Egípcio usando massa de couve-flor e ficou perfeita. Zero carboidrato e mata a vontade. É só ser criativo.', 'statement', NULL, '2026-03-05 14:20:24'),
(1410, 1, 19, 2366, NULL, 1, 'Debora K.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Debora+K.1&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Debora K.1', 'impressionante isso 🙌', 'reaction', 1403, '2026-03-05 14:20:36'),
(1411, 1, 17, 2330, NULL, 6, 'Claudio D.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Claudio+D.6&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Claudio D.6', 'Alguém já sentiu uma melhora na qualidade do cabelo e das unhas nas primeiras semanas de Protocolo? Estou notando meus cabelos mais fortes e minhas unhas menos quebradiças.', 'question', NULL, '2026-03-05 14:20:48'),
(1412, 1, 1, 2012, NULL, 4, 'Ingrid T.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ingrid+T.4&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Ingrid T.4', 'A consistência é mais importante que a perfeição. Pequenos desvios são esperados, o importante é retomar o Protocolo imediatamente. Não desistam.', 'tip', NULL, '2026-03-05 14:21:01'),
(1413, 1, 15, 2292, NULL, 3, 'Kaique R.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Kaique+R.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Kaique R.3', 'Minha família e amigos já nem me perguntam mais sobre dieta. Eles veem que o Protocolo Egípcio é meu estilo de vida e respeitam. É a consolidação social e familiar.', 'statement', NULL, '2026-03-05 14:21:13'),
(1414, 1, 18, 2348, NULL, 5, 'Lacerda S.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Lacerda+S.5&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Lacerda S.5', 'Cada um no seu tempo.', 'statement', 1409, '2026-03-05 14:21:25'),
(1415, 1, 16, 2312, NULL, 3, 'Italo L.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Italo+L.3&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Italo L.3', 'Fui convidado para dar uma entrevista em um podcast sobre minha jornada com o esse esquema.', 'statement', NULL, '2026-03-05 14:21:37'),
(1416, 1, 17, 2331, NULL, 2, 'Matheus G.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Matheus+G.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Matheus G.2', 'Sim, a melhora na qualidade do cabelo e das unhas é um efeito colateral positivo da otimização nutricional e hormonal. É um indicador de saúde interna.', 'answer', 1411, '2026-03-05 14:21:50'),
