(1478, 1, 22, 2422, NULL, 2, 'Diego H.', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Diego+H.2&backgroundColor=b6e3f4,c0aede,d1d4f9,ffd5dc,ffdfbf', 'Diego H.2', 'A redução de medidas e gordura localizada é um efeito da queima de gordura e da remodelação corporal.', 'statement', NULL, '2026-03-05 14:34:26'),
