INSERT INTO `timeline_messages` (`id`, `block_id`, `bot_id`, `archetype_id`, `resolved_name`, `message_type`, `content`, `reply_to_id`, `sequence_order`, `delay_after_prev`, `nivel_participacao`, `tempo_no_projeto`, `historico_interacoes`, `posted_at`, `created_at`) VALUES
(2000, 1, NULL, 4, NULL, 'tip', 'Para quem está no mês 2+: o momento de introduzir variação de carboidratos complexos é agora. O metabolismo já está adaptado.', NULL, 19, 10, 'avancado', 75, 50, '2026-03-05 11:40:20', '2026-03-05 13:14:56'),
(2001, 1, NULL, 4, NULL, 'tip', 'Refinamento técnico: gorduras boas antes da proteína demonstram redução adicional de 8-12% na nível de açúcar no sangue. Testem e observem.', NULL, 2, 15, 'avancado', 90, 65, '2026-03-05 10:22:39', '2026-03-05 13:14:56'),
(2002, 1, NULL, 4, NULL, 'tip', 'Atenção à hidratação no período pós-treino. A recuperação muscular é otimizada com a reposição eletrolítica adequada, sem quebrar o jejum metabólico.', NULL, 3, 12, 'avancado', 80, 55, '2026-03-05 10:29:47', '2026-03-05 13:14:56'),
(2003, 1, NULL, 4, NULL, 'tip', 'Para quem busca otimizar a queima de gordura, a inclusão de chás termogênicos específicos (sem açúcar) no período da manhã pode potencializar os resultados.', NULL, 4, 18, 'avancado', 100, 70, '2026-03-05 10:36:07', '2026-03-05 13:14:56'),
(2004, 1, NULL, 4, NULL, 'tip', 'Observamos que a qualidade do sono impacta diretamente a regulação hormonal e, consequentemente, a adesão e os resultados do Protocolo. Priorizem o descanso.', NULL, 5, 20, 'avancado', 110, 80, '2026-03-05 10:40:50', '2026-03-05 13:14:56'),
(2005, 1, NULL, 4, NULL, 'tip', 'Ajustes finos na proporção de fibras no jantar podem auxiliar na saciedade noturna e na manutenção do jejum. Experimentem diferentes fontes.', NULL, 6, 14, 'avancado', 95, 68, '2026-03-05 10:43:29', '2026-03-05 13:14:56'),
(2006, 1, NULL, 4, NULL, 'tip', 'Para quem sente fadiga no meio do dia, revisem a ingestão de micronutrientes. Uma suplementação direcionada pode ser benéfica, sempre com acompanhamento.', NULL, 7, 16, 'avancado', 120, 90, '2026-03-05 10:47:10', '2026-03-05 13:14:56'),
(2007, 1, NULL, 4, NULL, 'tip', 'A variação das fontes de proteína é crucial para evitar adaptação metabólica e garantir um espectro completo de aminoácidos. Não se limitem ao básico.', NULL, 8, 11, 'avancado', 85, 60, '2026-03-05 10:53:17', '2026-03-05 13:14:56'),
(2008, 1, NULL, 4, NULL, 'tip', 'Acompanhem a composição corporal, não apenas o peso. A perda de gordura e o ganho de massa magra são os indicadores mais importantes de sucesso no Protocolo.', NULL, 9, 19, 'avancado', 130, 95, '2026-03-05 11:00:02', '2026-03-05 13:14:56'),
(2009, 1, NULL, 4, NULL, 'tip', 'Para os mais avançados, a ciclagem de carboidratos em dias de treino intenso pode otimizar a performance sem comprometer a cetose metabólica. Estudem o timing.', NULL, 10, 22, 'avancado', 150, 100, '2026-03-05 11:06:09', '2026-03-05 13:14:56'),
(2010, 1, NULL, 4, NULL, 'tip', 'A gestão do estresse é um pilar esquecido. Níveis elevados de cortisol podem sabotar os resultados, mesmo com adesão perfeita ao Protocolo. Meditem, relaxem.', NULL, 11, 13, 'avancado', 140, 110, '2026-03-05 11:13:05', '2026-03-05 13:14:56'),
(2011, 1, NULL, 4, NULL, 'tip', 'Reavaliem a qualidade das suas gorduras. Óleos refinados e processados são inimigos do Protocolo. Priorizem fontes naturais e virgens.', NULL, 12, 17, 'avancado', 105, 72, '2026-03-05 11:17:21', '2026-03-05 13:14:56'),
(2012, 1, NULL, 4, NULL, 'tip', 'A consistência é mais importante que a perfeição. Pequenos desvios são esperados, o importante é retomar o Protocolo imediatamente. Não desistam.', NULL, 13, 21, 'avancado', 160, 120, '2026-03-05 11:21:01', '2026-03-05 13:14:56'),
(2013, 1, NULL, 4, NULL, 'tip', 'Para quem está estagnado, um \"reset\" de 24-48h com foco total em proteínas e gorduras pode reativar o metabolismo. Consultem um profissional para orientação.', NULL, 14, 25, 'avancado', 170, 115, '2026-03-05 11:27:31', '2026-03-05 13:14:56'),
(2014, 1, NULL, 4, NULL, 'tip', 'A inclusão de vegetais crucíferos na dieta pode auxiliar na desintoxicação e na otimização hormonal, complementando os efeitos do Protocolo.', NULL, 15, 10, 'avancado', 125, 88, '2026-03-05 11:29:21', '2026-03-05 13:14:56'),
(2015, 1, NULL, 4, NULL, 'tip', 'O timing da ingestão de água é crucial. Evitem grandes volumes durante as refeições para não diluir enzimas digestivas. Hidratem-se entre elas.', NULL, 16, 14, 'avancado', 135, 93, '2026-03-05 11:30:59', '2026-03-05 13:14:56'),
(2016, 1, NULL, 4, NULL, 'tip', 'Para quem sente fome excessiva, revisem a quantidade de proteína e gordura nas refeições. Elas são os pilares da saciedade no Protocolo Egípcio.', NULL, 17, 16, 'avancado', 145, 98, '2026-03-05 11:35:03', '2026-03-05 13:14:56'),
(2017, 1, NULL, 4, NULL, 'tip', 'A prática de exercícios de força é um excelente complemento ao Protocolo, auxiliando na manutenção da massa magra e na aceleração do metabolismo.', NULL, 18, 18, 'avancado', 155, 105, '2026-03-05 11:37:04', '2026-03-05 13:14:56'),
(2018, 1, NULL, 4, NULL, 'tip', 'Considerem a rotação de alimentos para evitar sensibilidades e garantir uma maior variedade de nutrientes. O corpo agradece a diversidade.', NULL, 1, 12, 'avancado', 165, 112, '2026-03-05 10:15:32', '2026-03-05 13:14:56'),
(2019, 1, NULL, 4, NULL, 'tip', 'Lembrem-se que o esse esquema é um estilo de vida. A adaptação e a escuta do próprio corpo são as chaves para o sucesso a longo prazo.', NULL, 20, 20, 'avancado', 180, 120, NULL, '2026-03-05 13:14:56'),
(2020, 2, NULL, 3, NULL, 'statement', 'Semana 6 aqui. Tive um plateau de 4 dias mas voltou ontem. Ajustei a proteína do jantar. Cara, o Protocolo é cirúrgico.', NULL, 1, 10, 'intermediario', 45, 25, '2026-03-05 10:15:19', '2026-03-05 13:14:56'),
(2021, 2, NULL, 1, NULL, 'reaction', 'Uhuuul! Que demais! 🥳 A gente sabe que funciona, mas ver o corpo respondendo assim é outra coisa! Parabéns! 💪', 2020, 2, 15, 'intermediario', 50, 30, '2026-03-05 10:16:08', '2026-03-05 13:14:56'),
(2022, 2, NULL, 2, NULL, 'statement', 'Interessante a observação sobre o plateau. Minha análise de dados mostra que ajustes na macro de proteína, especificamente, têm um impacto de 1.5x na quebra de estagnação em comparação com carboidratos.', NULL, 3, 12, 'avancado', 70, 50, '2026-03-05 10:16:33', '2026-03-05 13:14:56'),
(2023, 2, NULL, 5, NULL, 'answer', 'Exato. Pequenos ajustes fazem toda a diferença. É a beleza do o protocolo: ele te ensina a ler seu corpo. Qual foi o ajuste exato na proteína que você fez?', 2020, 4, 18, 'avancado', 80, 60, '2026-03-05 10:17:33', '2026-03-05 13:14:56'),
(2024, 2, NULL, 6, NULL, 'question', 'Aqui no grupo, á testou a inclusão de colágeno antes da proteína principal para otimizar a saciedade e a nível de açúcar no sangue? Estou avaliando a viabilidade.', NULL, 5, 20, 'avancado', 90, 70, '2026-03-05 10:18:22', '2026-03-05 13:14:56'),
(2025, 2, NULL, 2, NULL, 'answer', 'Sim, testei. Meus dados indicam uma redução de 7% na quantidade de calorias total na refeição subsequente e uma estabilização mais rápida da glicemia pós-prandial. É um bom complemento.', 2024, 6, 14, 'avancado', 95, 75, '2026-03-05 10:19:24', '2026-03-05 13:14:56'),
(2026, 2, NULL, 1, NULL, 'reaction', 'Que dica de ouro! ✨ Vou tentar isso! Sempre busco algo pra dar um boost na saciedade. O Protocolo é vida!', 2025, 7, 16, 'intermediario', 60, 35, '2026-03-05 10:20:49', '2026-03-05 13:14:56'),
(2027, 2, NULL, 3, NULL, 'statement', 'Mês 3 — colesterol LDL caiu mais 8 pontos. Médico pediu pra eu continuar exatamente assim. Mano, é surreal o que esse método faz.', NULL, 8, 11, 'avancado', 100, 80, '2026-03-05 10:22:15', '2026-03-05 13:14:56'),
(2028, 2, NULL, 5, NULL, 'statement', 'Excelente notícia! Isso reforça o que sempre falamos: o o método vai muito além da estética, é saúde plena. Compartilhem seus exames, inspira a todos!', 2027, 9, 19, 'avancado', 110, 85, '2026-03-05 10:23:16', '2026-03-05 13:14:56'),
