(2052, 3, NULL, 3, NULL, 'statement', 'Estava com dificuldade de manter a sequência em viagens. Comecei a levar meus próprios snacks de fibra e proteína. Resolveu 100%. É só se planejar, o Protocolo é flexível.', NULL, 13, 21, 'avancado', 145, 115, '2026-03-05 10:31:01', '2026-03-05 13:14:56'),
