(2161, 9, NULL, 1, NULL, 'reaction', 'Isso anima! 🤩 Reverter o pré-diabetes é uma conquista gigantesca! Você é uma inspiração! Parabéns! ✨', 2160, 2, 15, 'avancado', 155, 115, '2026-03-05 10:45:20', '2026-03-05 13:14:56'),
(2162, 9, NULL, 2, NULL, 'statement', 'A reversão da pré-diabetes é um dos benefícios mais significativos do Protocolo Egípcio, demonstrando a profunda melhora na sensibilidade à insulina e no controle glicêmico.', NULL, 3, 12, 'avancado', 170, 130, '2026-03-05 10:46:45', '2026-03-05 13:14:56'),
(2163, 9, NULL, 5, NULL, 'answer', 'Essa é a verdadeira evolução! O Protocolo Egípcio transformando a saúde de forma profunda. Compartilhe essa história, ela vai inspirar muitos!', 2160, 4, 18, 'avancado', 180, 135, '2026-03-05 10:47:34', '2026-03-05 13:14:56'),
