(2850, 43, NULL, 6, NULL, 'question', 'Para quem tem variação significativa nos horários de trabalho por turno ou plantão: como vocês adaptaram a janela alimentar sem perder a sequência do Protocolo?', NULL, 11, 13, 'avancado', 160, 102, NULL, '2026-03-05 13:14:56'),
(2851, 43, NULL, 2, NULL, 'answer', 'A solução é ancorar no ciclo de sono, não no relógio. Primeira refeição 1-2h após acordar, independente do horário. O metabolismo responde ao ritmo relativo, não ao horário absoluto.', 2850, 12, 17, 'avancado', 165, 108, NULL, '2026-03-05 13:14:56'),
(2852, 43, NULL, 3, NULL, 'statement', 'Trabalho em escala de plantão e essa dica do relógio relativo salvou meu Protocolo. Antes eu tentava forçar horários fixos absolutos e era uma batalha constante.', NULL, 13, 21, 'avancado', 170, 112, NULL, '2026-03-05 13:14:56'),
(2853, 43, NULL, 5, NULL, 'statement', 'Adaptações inteligentes como essa são o que mantém o Protocolo vivo em qualquer realidade de vida. A rigidez mata a adesão. A flexibilidade inteligente a preserva.', 2852, 14, 25, 'avancado', 180, 118, NULL, '2026-03-05 13:14:56'),
