(2927, 47, NULL, 3, NULL, 'statement', 'Minha pressão que vivia em 140x90 está em 120x80 há uma semana.', NULL, 8, 11, 'iniciante', 16, 8, NULL, '2026-03-05 13:14:56'),
(2928, 47, NULL, 5, NULL, 'statement', 'Queda de pressão na terceira semana! O Protocolo age rápido em pessoas com hipertensão. Continua monitorando e comunica ao médico. Esse tipo de resultado precisa de acompanhamento profissional.', 2927, 9, 19, 'intermediario', 45, 25, NULL, '2026-03-05 13:14:56'),
(2929, 47, NULL, 1, NULL, 'reaction', 'Brabo! 💪 O Protocolo impactando a pressão tão rápido! Continue monitorando! 🩺', 2928, 10, 22, 'iniciante', 14, 7, NULL, '2026-03-05 13:14:56'),
(2930, 47, NULL, 6, NULL, 'question', 'Para quem tomava suplementos antes do Protocolo: vocês mantiveram tudo, cortaram tudo ou fizeram uma curadoria? Não sei o que faz sentido manter nessa fase.', NULL, 11, 13, 'iniciante', 11, 6, NULL, '2026-03-05 13:14:56'),
(2931, 47, NULL, 2, NULL, 'answer', 'Curadoria é a abordagem certa. O Protocolo já fornece boa parte dos micronutrientes via alimentos de qualidade. O que geralmente faz sentido manter são magnésio, vitamina D3 e ômega-3. O restante avalia caso a caso.', 2930, 12, 17, 'intermediario', 48, 26, NULL, '2026-03-05 13:14:56'),
(2932, 47, NULL, 3, NULL, 'statement', 'Minha filha de 8 anos perguntou por que eu como diferente de todo mundo.', NULL, 13, 21, 'iniciante', 17, 9, NULL, '2026-03-05 13:14:56'),
(2933, 47, NULL, 5, NULL, 'statement', 'Que história encantadora! Crianças aprendem pelo exemplo, não pela instrução. Você está plantando uma semente poderosa. Que impacto de longo prazo!', 2932, 14, 25, 'intermediario', 50, 28, NULL, '2026-03-05 13:14:56');
INSERT INTO `timeline_messages` (`id`, `block_id`, `bot_id`, `archetype_id`, `resolved_name`, `message_type`, `content`, `reply_to_id`, `sequence_order`, `delay_after_prev`, `nivel_participacao`, `tempo_no_projeto`, `historico_interacoes`, `posted_at`, `created_at`) VALUES
(2934, 47, NULL, 1, NULL, 'reaction', 'Que fofo! 😍 Crianças sempre imitam quem amam! Você está formando um hábito saudável nela sem precisar de nada! 💖', 2933, 15, 10, 'iniciante', 13, 7, NULL, '2026-03-05 13:14:56'),
(2935, 47, NULL, 2, NULL, 'statement', 'A modelagem comportamental por figuras de referência é o mecanismo mais eficaz de formação de hábitos alimentares em crianças. O impacto do que você faz vai muito além de você.', NULL, 16, 14, 'intermediario', 52, 29, NULL, '2026-03-05 13:14:56'),
(2936, 47, NULL, 3, NULL, 'statement', 'Quase no fim do primeiro mês. 10kg a menos, roupas folgadas, energia constante, sono reparador. Se eu soubesse que o essa abordagem existia há 10 anos, teria começado antes.', NULL, 17, 16, 'iniciante', 19, 10, NULL, '2026-03-05 13:14:56'),
(2937, 47, NULL, 6, NULL, 'question', 'Alguém aqui começou o Protocolo depois dos 60 anos? Quero saber se a adaptação metabólica é mais lenta ou se o processo é similar ao de pessoas mais jovens.', NULL, 18, 18, 'iniciante', 9, 5, NULL, '2026-03-05 13:14:56'),
(2938, 47, NULL, 5, NULL, 'statement', 'Ótima pergunta! Temos membros de todas as idades com excelentes resultados. Quem começou depois dos 60 e pode compartilhar sua experiência de adaptação?', 2937, 19, 12, 'intermediario', 55, 30, NULL, '2026-03-05 13:14:56'),
(2939, 47, NULL, 1, NULL, 'reaction', 'Tenho 64 anos e comecei há 3 meses! 🙋‍♀️ Funcionou perfeitamente pra mim! Pode contar comigo se quiser trocar experiências! 💖', 2938, 20, 20, 'iniciante', 15, 8, NULL, '2026-03-05 13:14:56'),
(2940, 48, NULL, 3, NULL, 'statement', 'Percebi que meus resultados eram melhores quando eu dormia pelo menos 7h30. Nas semanas que durmi menos, o plateau aparecia. Sono é um ajuste tão importante quanto a comida no Protocolo.', NULL, 1, 10, 'intermediario', 65, 38, NULL, '2026-03-05 13:14:56'),
(2941, 48, NULL, 1, NULL, 'reaction', 'Que observação precisa! 🎯 O sono é o fator esquecido da equação! Também percebi isso! ✨', 2940, 2, 15, 'intermediario', 68, 41, NULL, '2026-03-05 13:14:56'),
(2942, 48, NULL, 2, NULL, 'statement', 'A privação de sono eleva cortisol, suprime leptina e aumenta grelina. O efeito metabólico de dormir mal equivale a um desvio significativo no Protocolo mesmo com adesão alimentar perfeita.', NULL, 3, 12, 'avancado', 130, 85, NULL, '2026-03-05 13:14:56'),
(2943, 48, NULL, 5, NULL, 'answer', 'Sono, estresse e alimentação formam o tripé do Protocolo na prática. Quem já tinha domínio das duas primeiras e precisou ajustar o sono para desbloquear resultados?', 2940, 4, 18, 'avancado', 140, 90, NULL, '2026-03-05 13:14:56'),
(2944, 48, NULL, 6, NULL, 'question', 'Para quem teve dificuldade com qualidade de sono: quais estratégias funcionaram dentro do contexto do Protocolo para melhorar sem recorrer a medicação?', NULL, 5, 20, 'avancado', 150, 98, NULL, '2026-03-05 13:14:56'),
(2945, 48, NULL, 2, NULL, 'answer', 'As estratégias mais eficazes que documentei: jantar leve e antecipado, magnésio glicinato 400mg antes de dormir, bloquear luz azul após 21h e manter temperatura do quarto entre 18 e 20 graus. Todas compatíveis com o Protocolo.', 2944, 6, 14, 'avancado', 155, 102, NULL, '2026-03-05 13:14:56'),
(2946, 48, NULL, 1, NULL, 'reaction', 'Que arsenal completo! 🙌 O magnésio me salvou o sono! Recomendo demais! 💤✨', 2945, 7, 16, 'intermediario', 72, 45, NULL, '2026-03-05 13:14:56'),
(2947, 48, NULL, 3, NULL, 'statement', 'Ajustei a quantidade de sal das refeições depois de perceber que estava retendo líquido. Reduzi e em 3 dias a retenção desapareceu. O Protocolo te ensina a ler o próprio corpo com precisão cirúrgica.', NULL, 8, 11, 'avancado', 160, 105, NULL, '2026-03-05 13:14:56'),
(2948, 48, NULL, 5, NULL, 'statement', 'Leitura fina do corpo é uma das maiores habilidades que o Protocolo desenvolve. Essa sensibilidade é um presente que vai além da alimentação. Parabéns pela percepção!', 2947, 9, 19, 'avancado', 170, 110, NULL, '2026-03-05 13:14:56'),
(2949, 48, NULL, 1, NULL, 'reaction', 'Exatamente! 💡 Aprendi a ouvir meu corpo de um jeito que nunca imaginei antes do Protocolo! ✨', 2948, 10, 22, 'intermediario', 75, 48, NULL, '2026-03-05 13:14:56'),
(2950, 48, NULL, 6, NULL, 'question', 'Curiosidade: á testou a diferença entre consumir a proteína do jantar em fonte animal versus vegetal em termos de impacto no sono e na recuperação muscular? Estou fazendo esse experimento.', NULL, 11, 13, 'avancado', 180, 115, NULL, '2026-03-05 13:14:56'),
(2951, 48, NULL, 2, NULL, 'answer', 'Meus dados pessoais indicam que proteína animal no jantar promove sono mais profundo, possivelmente pelo triptofano e glicina presentes em cortes como frango e peixe. Proteína vegetal foi menos conclusiva para mim.', 2950, 12, 17, 'avancado', 185, 120, NULL, '2026-03-05 13:14:56'),
(2952, 48, NULL, 3, NULL, 'statement', 'Comecei a incluir uma caminhada noturna leve, 15 minutos, depois do jantar. A digestão melhorou e a glicemia pós-prandial parece mais controlada. Sinto diferença no dia seguinte.', NULL, 13, 21, 'avancado', 190, 125, NULL, '2026-03-05 13:14:56'),
(2953, 48, NULL, 5, NULL, 'statement', 'A caminhada pós-jantar é uma adição poderosa. É um dos poucos exercícios com impacto direto na glicemia pós-prandial sem comprometer o estado metabólico do Protocolo. Ótima adição!', 2952, 14, 25, 'avancado', 200, 130, NULL, '2026-03-05 13:14:56'),
(2954, 48, NULL, 1, NULL, 'reaction', 'Comecei a fazer isso também! 🚶‍♀️ Faz uma diferença enorme no conforto digestivo! Recomendo! 💖', 2953, 15, 10, 'intermediario', 78, 50, NULL, '2026-03-05 13:14:56'),
(2955, 48, NULL, 2, NULL, 'statement', 'A caminhada de baixa intensidade pós-prandial ativa a translocação de GLUT4 muscular independentemente de insulina, resultando em captação de glicose mais eficiente e menor pico glicêmico.', NULL, 16, 14, 'avancado', 205, 135, NULL, '2026-03-05 13:14:56'),
(2956, 48, NULL, 3, NULL, 'statement', 'Mês 4 completo. 22kg a menos. Cada ajuste que faço no Protocolo me aproxima mais do resultado ideal. É uma dança entre o método e o meu corpo específico.', NULL, 17, 16, 'avancado', 210, 140, NULL, '2026-03-05 13:14:56'),
(2957, 48, NULL, 6, NULL, 'question', 'Pergunta pra galera: á tentou monitorar variabilidade da frequência cardíaca como indicador de recuperação e estado de estresse para ajustar a intensidade dos treinos dentro do Protocolo?', NULL, 18, 18, 'avancado', 220, 145, NULL, '2026-03-05 13:14:56'),
(2958, 48, NULL, 5, NULL, 'statement', 'VFC como ferramenta de autorregulação é sofisticado e muito eficaz! Quem usa e pode compartilhar como integra isso com os ajustes do Protocolo?', 2957, 19, 12, 'avancado', 230, 150, NULL, '2026-03-05 13:14:56'),
(2959, 48, NULL, 1, NULL, 'reaction', 'Cada vez mais impressionada com o nível da comunidade! 🤯 Aprendizados infinitos aqui! ❤️', 2958, 20, 20, 'avancado', 82, 54, NULL, '2026-03-05 13:14:56'),
(2960, 49, NULL, 3, NULL, 'statement', 'Mês 13. Perdi 38kg no total. Comecei a correr e fiz minha primeira corrida de 5km. Nunca corri na vida. O essa rotina me deu um corpo e uma saúde que eu nunca tive.', NULL, 1, 10, 'avancado', 390, 270, NULL, '2026-03-05 13:14:56'),
(2961, 49, NULL, 1, NULL, 'reaction', '38kg e primeira corrida de 5km! 🏃‍♀️🎉 Você escreveu uma história nova para si mesmo! Que emoção enorme! 💖', 2960, 2, 15, 'avancado', 395, 275, NULL, '2026-03-05 13:14:56'),
(2962, 49, NULL, 2, NULL, 'statement', 'A capacidade de correr 5km após perda significativa de peso é um indicador composto de melhora cardiovascular, muscular e articular. É um resultado que valida a preservação da qualidade do tecido ao longo do processo.', NULL, 3, 12, 'avancado', 410, 290, NULL, '2026-03-05 13:14:56'),
(2963, 49, NULL, 5, NULL, 'answer', 'Primeiro 5km é uma das marcas mais simbólicas de transformação! O Protocolo Egípcio criou o terreno para isso. Que história você vai contar para seus netos!', 2960, 4, 18, 'avancado', 420, 295, NULL, '2026-03-05 13:14:56'),
(2964, 49, NULL, 6, NULL, 'question', 'Para quem incorporou corrida ou exercício aeróbico intenso depois de muito tempo sedentário: como ajustaram a alimentação do Protocolo para suportar o aumento de demanda sem comprometer a queima de gordura?', NULL, 5, 20, 'avancado', 430, 300, NULL, '2026-03-05 13:14:56'),
(2965, 49, NULL, 2, NULL, 'answer', 'O ajuste principal é aumentar proteína nos dias de treino intenso em 20 a 30% para suportar recuperação muscular. Carboidratos complexos em quantidade mínima pré-treino apenas se o volume for muito alto. Gorduras permanecem como base de energia.', 2964, 6, 14, 'avancado', 435, 305, NULL, '2026-03-05 13:14:56'),
(2966, 49, NULL, 1, NULL, 'reaction', 'Que orientação clara! 🙌 Anotar isso aqui! Obrigada! 🏃‍♀️✨', 2965, 7, 16, 'avancado', 400, 280, NULL, '2026-03-05 13:14:56'),
(2967, 49, NULL, 3, NULL, 'statement', 'Minha vitamina D saiu de 18 pra 62.', NULL, 8, 11, 'avancado', 440, 310, NULL, '2026-03-05 13:14:56'),
(2968, 49, NULL, 5, NULL, 'statement', 'Exatamente esse efeito cascata! Um hábito puxa o outro. O Protocolo na alimentação se expande para movimento, sono, exposição solar e bem-estar mental. É uma espiral ascendente.', 2967, 9, 19, 'avancado', 450, 315, NULL, '2026-03-05 13:14:56'),
(2969, 49, NULL, 1, NULL, 'reaction', 'Espiral ascendente! 🌀 Que imagem perfeita pra descrever o Protocolo! Amei! ✨', 2968, 10, 22, 'avancado', 405, 285, NULL, '2026-03-05 13:14:56'),
(2970, 49, NULL, 6, NULL, 'question', 'Pergunta pra galera: á correlacionou seus níveis de energia subjetivos com os dados de exame de ferro, ferritina e vitamina B12 durante o Protocolo? Estou investigando se esses marcadores explicam variações no meu desempenho.', NULL, 11, 13, 'avancado', 460, 320, NULL, '2026-03-05 13:14:56'),
(2971, 49, NULL, 2, NULL, 'answer', 'Sim, ferro e ferritina são marcadores frequentemente subótimos mesmo sem anemia formal. Ferritina abaixo de 50 já compromete energia e performance. Vale checar e otimizar dentro do Protocolo se necessário.', 2970, 12, 17, 'avancado', 465, 325, NULL, '2026-03-05 13:14:56'),
(2972, 49, NULL, 3, NULL, 'statement', 'Meu endocrinologista me disse que eu sou o paciente com melhor evolução metabólica que ele acompanhou nos últimos cinco anos.', NULL, 13, 21, 'avancado', 470, 330, NULL, '2026-03-05 13:14:56'),
(2973, 49, NULL, 5, NULL, 'statement', 'Validação médica consistente! Isso é o Protocolo sendo reconhecido onde mais importa. Que resultado extraordinário. Compartilhe essa história sempre que puder!', 2972, 14, 25, 'avancado', 480, 335, NULL, '2026-03-05 13:14:56'),
(2974, 49, NULL, 1, NULL, 'reaction', 'Melhor paciente do endócrino! 🏆 Que distinção incrível! O Protocolo fala por você! 💪', 2973, 15, 10, 'avancado', 410, 290, NULL, '2026-03-05 13:14:56'),
(2975, 49, NULL, 2, NULL, 'statement', 'O reconhecimento de endocrinologistas é especialmente relevante porque são os especialistas mais próximos do metabolismo. Quando um endócrino elogia a evolução do paciente, o método está funcionando em nível profundo.', NULL, 16, 14, 'avancado', 485, 340, NULL, '2026-03-05 13:14:56'),
(2976, 49, NULL, 3, NULL, 'statement', 'Comecei a nadar. Aos 58 anos. Pela primeira vez na vida. O Protocolo Egípcio me devolveu a capacidade de descobrir novas possibilidades físicas. Sinto que envelheci ao contrário.', NULL, 17, 16, 'avancado', 490, 345, NULL, '2026-03-05 13:14:56'),
(2977, 49, NULL, 6, NULL, 'question', 'Alguém explorou a conexão entre o Protocolo e a melhora de condições autoimunes como hipotireoidismo de Hashimoto ou artrite reumatoide? Tenho Hashimoto e estou observando mudanças interessantes.', NULL, 18, 18, 'avancado', 500, 350, NULL, '2026-03-05 13:14:56'),
(2978, 49, NULL, 5, NULL, 'statement', 'Condições autoimunes e Protocolo é um campo rico de relatos nesta comunidade. Quem tem experiências com Hashimoto, artrite ou outras condições autoimunes, compartilhe com cuidado e sempre com acompanhamento médico!', 2977, 19, 12, 'avancado', 510, 355, NULL, '2026-03-05 13:14:56'),
(2979, 49, NULL, 1, NULL, 'reaction', 'Que tópico importante! 🙏 Tenho Hashimoto também e percebo melhoras! Vou compartilhar minha experiência em breve! 💖', 2978, 20, 20, 'avancado', 415, 295, NULL, '2026-03-05 13:14:56'),
(2980, 50, NULL, 3, NULL, 'statement', 'Mês 30. Dois anos e meio. O isso aqui já não é um método, é minha linguagem. Assim como falo português sem pensar, me alimento assim sem esforço. É identidade pura.', NULL, 1, 10, 'avancado', 900, 620, NULL, '2026-03-05 13:14:56'),
(2981, 50, NULL, 1, NULL, 'reaction', 'Dois anos e meio! 🎂 E essa metáfora com o idioma é perfeita! O Protocolo virou sua língua materna! ✨', 2980, 2, 15, 'avancado', 905, 625, NULL, '2026-03-05 13:14:56'),
(2982, 50, NULL, 2, NULL, 'statement', 'A comparação com fluência linguística é tecnicamente precisa. Quando um comportamento deixa de exigir processamento consciente e opera em modo automático, é porque foi consolidado em memória implícita de procedimento.', NULL, 3, 12, 'avancado', 920, 640, NULL, '2026-03-05 13:14:56'),
(2983, 50, NULL, 5, NULL, 'answer', 'Dois anos e meio de fluência total no Protocolo. Isso é o que a consolidação parece na prática. Que mensagem você deixa para quem está no mês 2 achando difícil?', 2980, 4, 18, 'avancado', 930, 645, NULL, '2026-03-05 13:14:56'),
(2984, 50, NULL, 6, NULL, 'question', 'Para quem está na consolidação longa: vocês percebem que o Protocolo continua trazendo novos benefícios mesmo depois de anos? Ou os benefícios se estabilizam em um platô positivo?', NULL, 5, 20, 'avancado', 940, 650, NULL, '2026-03-05 13:14:56'),
(2985, 50, NULL, 2, NULL, 'answer', 'Minha observação em 3 anos é que os benefícios primários se estabilizam por volta do mês 18, mas benefícios secundários e terciários continuam emergindo. É uma colheita contínua de uma plantação que já fez raízes profundas.', 2984, 6, 14, 'avancado', 945, 655, NULL, '2026-03-05 13:14:56'),
(2986, 50, NULL, 1, NULL, 'reaction', 'Que metáfora linda da plantação! 🌱 Benefícios emergindo anos depois! O Protocolo é de longo prazo mesmo! ✨', 2985, 7, 16, 'avancado', 910, 630, NULL, '2026-03-05 13:14:56'),
(2987, 50, NULL, 3, NULL, 'statement', 'Fui em uma festa de reencontro de amigos que não via há 3 anos. Ninguém me reconheceu de cara. Quando me apresentei, o silêncio foi total. Depois vieram as perguntas. Foram 2 horas falando sobre o Protocolo.', NULL, 8, 11, 'avancado', 950, 660, NULL, '2026-03-05 13:14:56'),
(2988, 50, NULL, 5, NULL, 'statement', 'Não ser reconhecido por amigos é o marcador mais humano da transformação profunda. Parabéns pela sua jornada e por ser essa prova viva do Protocolo!', 2987, 9, 19, 'avancado', 960, 665, NULL, '2026-03-05 13:14:56'),
(2989, 50, NULL, 1, NULL, 'reaction', 'Que cena poderosa! 😭 Dois horas de Protocolo no reencontro! Você é literalmente o Protocolo andando! 💖', 2988, 10, 22, 'avancado', 915, 635, NULL, '2026-03-05 13:14:56'),
(2990, 50, NULL, 6, NULL, 'question', 'Alguém com mais de 2 anos de Protocolo já revisitou algum exame de marcadores inflamatórios como PCR ou IL-6 e observou evolução ao longo do tempo? Buscando dados de longo prazo sobre inflamação no corpo.', NULL, 11, 13, 'avancado', 970, 670, NULL, '2026-03-05 13:14:56'),
(2991, 50, NULL, 2, NULL, 'answer', 'Sim, minha PCR ultrassensível caiu de 4.2 para 0.4 ao longo de 2 anos. IL-6 não medido por custo, mas a PCR é um proxy razoável. A trajetória é consistentemente descendente com o Protocolo mantido.', 2990, 12, 17, 'avancado', 975, 675, NULL, '2026-03-05 13:14:56'),
(2992, 50, NULL, 3, NULL, 'statement', 'Há dois anos e meio não tomo nenhum remédio. Antes eram 4 medicações diárias. A última saiu há 8 meses sob supervisão médica. O Protocolo Egípcio me devolveu a autonomia da saúde.', NULL, 13, 21, 'avancado', 980, 680, NULL, '2026-03-05 13:14:56'),
(2993, 50, NULL, 5, NULL, 'statement', 'Sair de 4 medicações para zero em dois anos e meio, com supervisão médica, é um resultado que precisa ser documentado. Isso é medicina preventiva no seu melhor. Parabéns pela sua disciplina!', 2992, 14, 25, 'avancado', 990, 685, NULL, '2026-03-05 13:14:56'),
(2994, 50, NULL, 1, NULL, 'reaction', 'Zero medicação! 🙌 Isso é liberdade total! Que conquista incrível! Parabéns! 💖', 2993, 15, 10, 'avancado', 920, 640, NULL, '2026-03-05 13:14:56'),
(2995, 50, NULL, 2, NULL, 'statement', 'A reversão da polifarmácia por intervenção de estilo de vida é um dos resultados de maior impacto clínico e econômico. Representa também a maior evidência da efetividade de longo prazo do Protocolo.', NULL, 16, 14, 'avancado', 995, 690, NULL, '2026-03-05 13:14:56'),
(2996, 50, NULL, 3, NULL, 'statement', 'Planejei uma viagem de trekking de 10 dias nas montanhas. Há 3 anos mal conseguia caminhar 500 metros. O isso aqui não me deu apenas saúde, me devolveu a aventura.', NULL, 17, 16, 'avancado', 1000, 695, NULL, '2026-03-05 13:14:56'),
(2997, 50, NULL, 6, NULL, 'question', 'Rola aqui também? á fez um exercício de calcular quantos anos de vida qualitativa o Protocolo potencialmente adicionou à sua trajetória, considerando a reversão de condições crônicas? Tenho tentado mensurar isso.', NULL, 18, 18, 'avancado', 1010, 700, NULL, '2026-03-05 13:14:56'),
(2998, 50, NULL, 5, NULL, 'statement', 'Medir anos de vida qualitativa recuperados é o exercício mais motivador que existe. Quem fez esse cálculo, compartilhe. Vai inspirar quem está no começo a entender o real tamanho do que está construindo.', 2997, 19, 12, 'avancado', 1020, 705, NULL, '2026-03-05 13:14:56'),
(2999, 50, NULL, 1, NULL, 'reaction', 'Que perspectiva profunda! 🥺 O Protocolo como investimento de vida. Emocionada demais! ❤️', 2998, 20, 20, 'avancado', 925, 645, NULL, '2026-03-05 13:14:56'),
(3000, 51, NULL, 3, NULL, 'statement', 'Lancei um podcast sobre saúde metabólica onde entrevisto pessoas que transformaram a vida com o Protocolo Egípcio.', NULL, 1, 10, 'avancado', 1020, 710, NULL, '2026-03-05 13:14:56'),
(3001, 51, NULL, 1, NULL, 'reaction', 'Podcast com 40 mil ouvintes! 🎙️🤩 Você construiu um movimento! Isso é liderança em outro nível! ✨', 3000, 2, 15, 'avancado', 1025, 715, NULL, '2026-03-05 13:14:56'),
(3002, 51, NULL, 2, NULL, 'statement', 'A escala de impacto via podcast combina alcance amplo com profundidade de conteúdo. É o formato ideal para transmitir nuances que posts curtos não conseguem capturar. Excelente canal de liderança.', NULL, 3, 12, 'avancado', 1040, 730, NULL, '2026-03-05 13:14:56'),
(3003, 51, NULL, 5, NULL, 'answer', 'Que iniciativa extraordinária! Como você seleciona os convidados e quais histórias têm gerado mais impacto junto ao público?', 3000, 4, 18, 'avancado', 1050, 735, NULL, '2026-03-05 13:14:56'),
(3004, 51, NULL, 6, NULL, 'question', 'Para quem cria conteúdo sobre o Protocolo: como vocês abordam a responsabilidade de influenciar decisões de saúde de outras pessoas sem extrapolar o papel de quem compartilha experiência e não de quem prescreve?', NULL, 5, 20, 'avancado', 1060, 740, NULL, '2026-03-05 13:14:56'),
(3005, 51, NULL, 2, NULL, 'answer', 'A fronteira está em sempre contextualizar como relato pessoal, nunca como prescrição. Incentivar acompanhamento profissional em todas as situações que envolvem medicações ou condições diagnosticadas. Isso protege o público e credibiliza quem fala.', 3004, 6, 14, 'avancado', 1065, 745, NULL, '2026-03-05 13:14:56'),
(3006, 51, NULL, 1, NULL, 'reaction', 'Que postura ética! 👏 Essa responsabilidade é fundamental para quem influencia pessoas. Aprendizado valioso! 🙏', 3005, 7, 16, 'avancado', 1030, 720, NULL, '2026-03-05 13:14:56'),
(3007, 51, NULL, 3, NULL, 'statement', 'Uma seguidora me enviou uma mensagem dizendo que meu conteúdo sobre o Protocolo salvou o casamento dela. Marido e mulher transformaram a saúde juntos, melhoraram a autoestima e reaproximaram um do outro. Isso me deu a certeza que vale a pena continuar.', NULL, 8, 11, 'avancado', 1070, 750, NULL, '2026-03-05 13:14:56'),
(3008, 51, NULL, 5, NULL, 'statement', 'O Protocolo impactando relacionamentos, famílias, vida a dois. Isso é o efeito sistêmico da transformação individual. Cada pessoa que muda muda o sistema ao redor. Continue compartilhando!', 3007, 9, 19, 'avancado', 1080, 755, NULL, '2026-03-05 13:14:56'),
